content.text:
Claude returns a data structure like this:

{
  "message": "The methodology used a randomized controlled trial design [p. 45]. Key findings showed 25% improvement [pp. 78-82]."
  "citations": [
    {
      "cited_text": "The methodology used a randomized controlled trial design.",
      "document_title": "research_paper.pdf",
      "start_page_number": 45,
      "end_page_number": 45,
      "document_index": 0
    },
    {
      "cited_text": "Key findings showed 25% improvement in outcomes.",
      "document_title": "research_paper.pdf",
      "start_page_number": 78,
      "end_page_number": 82,
      "document_index": 0
    }
  ]
}

import anthropic

client = anthropic.Anthropic()

# Get response with citations
response = client.messages.create(
    model="claude-3-5-sonnet-20241022",
    max_tokens=1024,
    messages=[{
        "role": "user",
        "content": [
            {
                "type": "document",
                "source": {
                    "type": "base64",
                    "media_type": "application/pdf",
                    "data": encoded_pdf
                },
                "title": "research_paper.pdf",
                "citations": {"enabled": True}
            },
            {
                "type": "text",
                "text": "What were the key findings?"
            }
        ]
    }]
)

# STEP 1: Read the text response (includes inline citations)
text_response = response.content[0].text
print("Response:")
print(text_response)

# Output:
# "The methodology used a randomized controlled trial design [p. 45].
#  Key findings showed 25% improvement in outcomes [pp. 78-82]."

# STEP 2: Access citation metadata
print("\nCitations:")
for citation in response.citations:
    print(f"  Cited text: {citation.cited_text}")
    print(f"  Source: {citation.document_title} [p. {citation.start_page_number}]")
    print(f"  Document index: {citation.document_index}")

# Parse JSON response from API
response_json = {
    "content": [
        {
            "type": "text",
            "text": "The methodology used a randomized controlled trial design [p. 45]."
        }
    ],
    "citations": [
        {
            "cited_text": "The methodology used a randomized controlled trial design.",
            "document_title": "research_paper.pdf",
            "start_page_number": 45,
            "end_page_number": 45,
            "document_index": 0,
            "cited_location": {
                "type": "page",
                "start_page_number": 45,
                "end_page_number": 45
            }
        }
    ]
}

# Extract text response
text_response = response_json["content"][0]["text"]
print(f"Response: {text_response}")

# Extract citations
for citation in response_json["citations"]:
    print(f"\nCited text: {citation['cited_text']}")
    print(f"Source: {citation['document_title']} [p. {citation['start_page_number']}]")

citation_loc = citation['cited_location']

if citation_loc['type'] == 'page':
    location = f"[p. {citation_loc['start_page_number']}]"
elif citation_loc['type'] == 'char':
    location = f"[chars {citation_loc['start_char']}-{citation_loc['end_char']}]"
elif citation_loc['type'] == 'block':
    location = f"[block {citation_loc['start_block']}]"

print(f"{citation['cited_text']} {location}")
